import{_ as t,o,c as n,a3 as r}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"28. Termination Of Employment","description":"","frontmatter":{"title":"28. Termination Of Employment","eba":"Mental Health Services 2024-2028","topics":["leave","long-service-leave","wages","employment","termination"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/employment-types/28-termination-of-employment.md","filePath":"ebas/mental-health/common-terms/employment-types/28-termination-of-employment.md"}'),a={name:"ebas/mental-health/common-terms/employment-types/28-termination-of-employment.md"};function i(s,e,p,m,l,h){return o(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="_28-termination-of-employment" tabindex="-1">28. Termination Of Employment <a class="header-anchor" href="#_28-termination-of-employment" aria-label="Permalink to &quot;28. Termination Of Employment&quot;">​</a></h1><p><strong>28.1</strong> Notice Period/Payment in Lieu</p><p><strong>(a)</strong> An Employer may terminate the employment of an Employee by providing 4 weeks&#39; notice in writing.</p><p><strong>(b)</strong> The notice required by sub-clause 28.1(a) will be increased by 1 week if the Employee is over 45 years of age and has completed more than 2 years of continuous service.</p><p><strong>(c)</strong> Continuous service for the purpose of this clause has the same meaning as it does under <a href="/eba/ebas/mental-health/common-terms/leave/47-long-service-leave.html">clause 47</a> (Long Service Leave) and will include prior continuous service preceding a transfer of business, except in respect of any period of continuous service for which notice has already been given or paid.</p><p><strong>(d)</strong> An Employer may make payment in lieu of notice for part or all of the notice period. The payment in lieu of notice must equal or exceed the total of all amounts that the Employer would have paid had the Employee&#39;s employment continued until the end of the required notice period. That payment must be calculated on the basis of:</p><p><strong>(i)</strong> the Employee&#39;s ordinary hours of work (even if not standard hours);</p><p><strong>(ii)</strong> the amounts ordinarily payable to the Employee in respect of those hours, including (for example) allowances, loading and penalties; and</p><p><strong>(iii)</strong> any other amounts payable under the Employee&#39;s contract of employment.</p><p><strong>(e)</strong> An Employee may terminate their employment by providing 4 weeks&#39; notice to the Employer in writing. Subject to additional financial obligations imposed on the Employer by any legislation, if an Employee fails to give the required notice and the Employer had not agreed to a shorter notice period, the Employer has a right to deduct no more than one week’s wage due to the Employee provided that the deduction is not unreasonable in the circumstances.</p><p><strong>28.2</strong> Sub-clauses 28.1 and 28.3 above do not affect an Employer&#39;s right to terminate any Employee without notice for serious misconduct.</p><p><strong>28.3</strong> Sub-clause 28.1 - above of this Agreement does not apply:</p><p><strong>(a)</strong> to an Employee engaged under a fixed term contract</p><p><strong>(b)</strong> Employees engaged for a specific period of time or for a specific task or tasks</p><p><strong>(c)</strong> trainees whose employment under a traineeship agreement or an approved traineeship is for a specified period or is, for any other reason, limited to the duration of the agreement; or</p><p><strong>(d)</strong> casual employees.</p><p><strong>28.4</strong> Time off work during notice period Where the Employer has given notice of termination to an Employee (other than a casual employee), an Employee will be allowed up to one day&#39;s time off without loss of pay for the purpose of seeking other employment. The time off will be taken at times that are convenient to the Employee after consultation with the Employer.</p><p><strong>28.5</strong> Certificate of Service on termination A certificate of service including the information at <a href="/eba/ebas/mental-health/schedules/09-certificate-of-service.html">Schedule 9</a> will be provided to the Employee wherever practicable within 14 days of the date of termination including where a full-time or part-time Employee terminates employment and becomes a casual Employee.</p><p><strong>28.6</strong> Return of Property</p><p><strong>(a)</strong> Employees, on cessation of their employment, must return to their Employer the Employer’s property.</p><p><strong>(b)</strong> An Employee who is provided any property by their Employer at or after the time of their starting employment, may be required to complete a document provided by that Employer that outlines:</p><p><strong>(i)</strong> The details and dollar value of the property as at the time provided</p><p><strong>(ii)</strong> That the item at all times remains the property of the Employer</p><p><strong>(iii)</strong> That the Employee agrees to return the provided property to the Employer on cessation of their Employment; and</p><p><strong>(iv)</strong> That should the provided property not be returned at the cessation of employment, the Employer reserves the right to seek to recover the value of the property.</p><p>Plain language terms: resignation, dismissal, notice of termination, end of employment.</p>',26)])])}const y=t(a,[["render",i]]);export{c as __pageData,y as default};
